int set[100] = {0};
set[5] = 1;
set[10] = 1;
set[5] = 1;  // already in set, no effect

if (set[5])  printf("5 is in set\n");   // yes
if (!set[7]) printf("7 not in set\n");  // yes

set[5] = 0;  // remove
if (!set[5]) printf("5 removed\n");     // yes

