int nums[] = {1, 3, 5, 3, 7, 1};
int n = 6;
int seen[100] = {0};
for (int i = 0; i < n; i++) {
    if (seen[nums[i]]) {
        printf("%d is duplicate\n", nums[i]);
    }
    seen[nums[i]] = 1;
}
// 3 is duplicate
// 1 is duplicate

