int main() {
    unsigned int set = 0;
    set |= (1 << 1);
    set |= (1 << 4);
    set |= (1 << 6);

    if (set & (1 << 4)) printf("yes\n");
    if (!(set & (1 << 5))) printf("no\n");

    set &= ~(1 << 4);
    if (!(set & (1 << 4))) printf("removed\n");
    return 0;
}

