unsigned int b = (1 << 2) | (1 << 3) | (1 << 4);  // {2,3,4}

unsigned int u = a | b;   // union: {1,2,3,4}
unsigned int inter = a & b; // intersection: {2,3}
unsigned int diff = a & ~b; // difference: {1}

for (int i = 0; i < 8; i++)
    if (inter & (1 << i)) printf("%d ", i);
// 2 3

exercise.starterCode:
int main() {
    unsigned int a = (1 << 1) | (1 << 3) | (1 << 5);
    unsigned int b = (1 << 3) | (1 << 5) | (1 << 7);

    unsigned int inter = a & b;
    unsigned int uni = a | b;

    for (int i = 0; i < 8; i++)
        if (inter & (1 << i)) printf("%d ", i);
    printf("\n");

    for (int i = 0; i < 8; i++)
        if (uni & (1 << i)) printf("%d ", i);
    printf("\n");
    return 0;
}
